// // This module decrements the counter on each positive edge of the clock and resets to 7 when the reset signal is asserted.
module synchronous_counter(
    input CLK,
    input RST,
    output reg [3:0] Q
);

    always @(posedge CLK) begin
        if (RST == 1) begin
            Q <= 4'b0000;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
